solution_code:
#include <iostream>
#include <vector>

std::vector<int> keepPositives(std::vector<int> v)
{
    std::vector<int> result;
    for (int i = 0; i < static_cast<int>(v.size()); ++i)
    {
        if (v[i] > 0)
            result.push_back(v[i]);
    }
    return result;
}

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> data;
    for (int i = 0; i < n; ++i)
    {
        int x;
        std::cin >> x;
        data.push_back(x);
    }

    std::vector<int> positives { keepPositives(data) };
    for (int i = 0; i < static_cast<int>(positives.size()); ++i)
    {
        if (i > 0) std::cout << ' ';
        std::cout << positives[i];
    }
    std::cout << '\n';
    return 0;
}

